import React, { useState, useEffect } from "react";

//expandable with a list https://hlstore.ru/catalog/
//tempalte for one good
const ExpandableItem = ({ title, contentArr, setCategory }) => {
  const [expanded, setExpanded] = useState(false);

  const handleToggle = () => {
    setExpanded(!expanded);
  };

  return (
    <div className={`expandable-element ${expanded ? "expanded" : ""}`}>
      <div onClick={handleToggle}>
        <h3 className="expandable_h3">{title}</h3>
      </div>
      {expanded
        ? contentArr?.map((item) => {
            return (
              <>
                <p
                  onClick={() => {
                    setCategory(item);
                  }}
                >{`Item: ${item}`}</p>
                <br />
              </>
            );
          })
        : ""}
    </div>
  );
};

function ShopMain() {
  const goodsArr = { accessories: ["acc1", "acc2"], oils: ["oils1", "oils2"] };
  const [category, setCategory] = useState("");
  const [path, setPath] = useState("Главная");
  useEffect(() => {
    setPath(path + category);
  }, [category]);
  console.log(category);
  return (
    <>
      <h1 className="sub-header">
        Каталог товаров
        {/* {category} */}
      </h1>
      <div className="catalogue">
        <div className="list">
          <div className="catalogue-list-expandable">
            <ExpandableItem
              setCategory={setCategory}
              title="Всё для татуировки"
              contentArr={["Аксессуары", "Вазелин и масла"]}
            />
          </div>
          <div className="catalogue-list-expandable">
            {/* <ExpandableItem title="Всё для пирсинга" contentArr={} /> */}
            {goodsArr[category == "Аксессуары" ? "accessories" : "oils"]}
          </div>
        </div>
        <div className="filter-options"></div>
        <div className="goods"></div>
      </div>
    </>
  );
}

export default ShopMain;
